insert tb_cs_train (
	schedule_seq
	, name
	, model_id
	, data_cnt
	, requested_at
	, status
) value(
	#{scheduleSeq}
	, #{name}
	, #{modelId}
	, #{dataCnt}
	, CURRENT_TIMESTAMP
	, #{status}
)

