mapper.select:
select ts.seq AS seq , ts.start_time as startTime , ts.created_at as createdAt , tt.started_at AS startedAt , tt.ended_at AS endedAt , tt.is_success as isSuccess , tt.status as status ,( SELECT count(tsc.seq) FROM tb_cs_train_schedule tsc LEFT JOIN tb_cs_train ttc ON tsc.seq = ttc.schedule_seq
tsc.created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND tsc.seq = #{seq}
AND ttc.is_success = #{isSuccess}
) AS hiddenCount from tb_cs_train_schedule ts LEFT JOIN tb_cs_train tt ON ts.seq = tt.schedule_seq
ts.created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND ts.seq = #{seq}
AND tt.is_success = #{isSuccess}
order by startTime DESC
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select seq AS seq , name , model_id AS modelId , started_at AS startedAt , ended_at AS endedAt , (CONVERT(duration, SIGNED)) AS duration , status , is_success as isSuccess , cer , wer , '' AS detail , created_at as createdAt , updated_at as updatedAt ,( SELECT count(tra.seq) FROM tb_cs_train tra
and tra.created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
and tra.seq = #{seq}
) AS hiddenCount from tb_cs_train
and created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
and seq = #{seq}
order by requested_at DESC
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

SELECT re. data_id AS dataId , te.division As division , re.cer , re.entire_char as entireChar , re.error_char as errorChar , re.train_text AS trainText , re.stt_text AS sttText , tr.seq AS seq , tr.start , tr.end , tr.reliability , tr.test_seq AS testSeq , te.file_org_nm AS fileOrgNm , te.file_new_nm AS fileNewNm , te.subject as subject ,( SELECT count(reh.data_id) FROM tb_cs_train_result reh JOIN tb_cs_test_trans trh ON reh.data_id = trh.data_id JOIN tb_cs_test teh ON teh.seq != -1 AND trh.test_seq = teh.seq WHERE reh.model_id = #{modelId} ) AS hiddenCount FROM tb_cs_train_result re JOIN tb_cs_test_trans tr ON re.data_id = tr.data_id JOIN tb_cs_test te ON te.seq != -1 AND tr.test_seq = te.seq WHERE re.model_id = #{modelId}
order by te.file_new_nm desc
order by re.cer desc
order by te.created_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

